import{i as e,o as t,r as n,t as r}from"./app-CBUARAz9.js";var i=JSON.parse(`{"path":"/guide/bundle-export.html","title":"Bundle Products Export to Ebay","lang":"en-US","frontmatter":{},"git":{"updatedTime":1781613128000,"contributors":[{"name":"Mohd Munassir Alam","username":"","email":"munassir.alam632@webkul.in","commits":2},{"name":"Cursor","username":"Cursor","email":"cursoragent@cursor.com","commits":2,"url":"https://github.com/Cursor"}],"changelog":[{"hash":"4d80512a2d48eae5e959cd0d6449378aae746968","time":1781613128000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"feat: improve docs site UI, quick start, and fix broken images","coAuthors":[{"name":"Cursor","email":"cursoragent@cursor.com"}]},{"hash":"e6022d8d0c65f68f2d91f229a556e88c5caf03ae","time":1781609985000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"feat: restructure docs like Webkul Power BI documentation site","coAuthors":[{"name":"Cursor","email":"cursoragent@cursor.com"}]}]},"filePathRelative":"guide/bundle-export.md"}`),a={name:`bundle-export.md`};function o(r,i,a,o,s,c){return t(),n(`div`,null,[...i[0]||=[e(`<h1 id="bundle-products-export-to-ebay" tabindex="-1"><a class="header-anchor" href="#bundle-products-export-to-ebay"><span>Bundle Products Export to Ebay</span></a></h1><p>The bundle product created on Magento 2 store can be easily exported to eBay. Thus, this can be done post-creation of the bundle product on Magento 2 Store.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/bundledproducts.png" alt="bundledproducts">After this admin needs to go to <strong>Map Product</strong> option, which will open a page\xA0**Mapped Products List, <strong>where admin can select ** Export to eBay.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Ebay-Connector-blog-4-1.png" alt="Ebay-Connector-blog-4-1"></p><p>So, this exported product can be seen on the eBay account under ** Sell&gt;All selling.**</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/My-eBay-All-Selling-1.png" alt="My eBay All Selling">So, on clicking the respective product you can find the product details on product page. Thus, the customer can select the products in the bundle to complete the bundle.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/03/Yoga-Kits-eBay.png" alt="Yoga Kits eBay"></p>`,7)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};